// Authorize Context - Combinar contexto completo do executor
const executorData = $('Lookup Identity').item.json;
const equipesData = $input.all();

const executorId = executorData.executor_id;
const executorNome = executorData.executor_nome;
const divisaoId = executorData.divisao_id;

// Extrair IDs das equipes
const equipesIds = equipesData.map(item => item.json.equipe_id).filter(id => id != null);

return {
  json: {
    executor_id: executorId,
    executor_nome: executorNome,
    divisao_id: divisaoId,
    equipes_ids: equipesIds,
    context_loaded: true
  }
};

// Router - Parse comandos e rotear
const text = $input.item.json.text || '';
const originalText = $input.item.json.original_text || '';
const context = $input.item.json;

// Padrões de comandos
const patterns = {
  vencendo: /^vencendo$/i,
  hoje: /^hoje$/i,
  status: /^status\s+(anda|prog|conc|canc|rpar)$/i,
  tarefa: /^tarefa\s+(.+)$/i,
  id: /^id\s+([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})$/i,
  ordem: /^ordem\s+(\d+)$/i,
  nota: /^nota\s+(\d+)$/i,
  si: /^si\s+(\d+)$/i,
  sap: /^sap\s+([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})$/i,
  chat: /^chat\s+([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})$/i
};

let intent = 'unknown';
let params = {};

// Verificar cada padrão
for (const [key, pattern] of Object.entries(patterns)) {
  const match = originalText.match(pattern);
  if (match) {
    intent = key;
    if (match.length > 1) {
      params.value = match[1];
    }
    break;
  }
}

return {
  json: {
    ...context,
    intent: intent,
    params: params,
    original_text: originalText
  }
};

// Extrair status do comando
const originalText = $input.item.json.original_text || '';
const match = originalText.match(/^status\s+(anda|prog|conc|canc|rpar)$/i);
const statusCodigo = match ? match[1].toUpperCase() : null;

return {
  json: {
    ...$input.item.json,
    status_codigo: statusCodigo
  }
};

// Extrair texto de busca
const originalText = $input.item.json.original_text || '';
const match = originalText.match(/^tarefa\s+(.+)$/i);
const searchText = match ? match[1].trim() : '';

// Sanitizar: remover caracteres perigosos
const sanitized = searchText.replace(/[;'"\\]/g, '');

return {
  json: {
    ...$input.item.json,
    search_text: sanitized
  }
};

// Extrair UUID
const originalText = $input.item.json.original_text || '';
const match = originalText.match(/^id\s+([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})$/i);
const taskId = match ? match[1] : null;

// Validar UUID
if (!taskId || !/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(taskId)) {
  throw new Error('UUID inválido');
}

return {
  json: {
    ...$input.item.json,
    task_id: taskId
  }
};

// Extrair número da ordem
const originalText = $input.item.json.original_text || '';
const match = originalText.match(/^ordem\s+(\d+)$/i);
const ordemNum = match ? match[1] : null;

// Validar: apenas números
if (!ordemNum || !/^\d+$/.test(ordemNum)) {
  throw new Error('Número de ordem inválido');
}

return {
  json: {
    ...$input.item.json,
    ordem_num: ordemNum
  }
};

// Extrair número da nota
const originalText = $input.item.json.original_text || '';
const match = originalText.match(/^nota\s+(\d+)$/i);
const notaNum = match ? match[1] : null;

if (!notaNum || !/^\d+$/.test(notaNum)) {
  throw new Error('Número de nota inválido');
}

return {
  json: {
    ...$input.item.json,
    nota_num: notaNum
  }
};

// Extrair número do SI
const originalText = $input.item.json.original_text || '';
const match = originalText.match(/^si\s+(\d+)$/i);
const siNum = match ? match[1] : null;

if (!siNum || !/^\d+$/.test(siNum)) {
  throw new Error('Número de SI inválido');
}

return {
  json: {
    ...$input.item.json,
    si_num: siNum
  }
};

// Extrair UUID da tarefa para SAP
const originalText = $input.item.json.original_text || '';
const match = originalText.match(/^sap\s+([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})$/i);
const taskId = match ? match[1] : null;

if (!taskId || !/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(taskId)) {
  throw new Error('UUID inválido');
}

return {
  json: {
    ...$input.item.json,
    task_id: taskId
  }
};

// Extrair UUID da tarefa para chat
const originalText = $input.item.json.original_text || '';
const match = originalText.match(/^chat\s+([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})$/i);
const taskId = match ? match[1] : null;

if (!taskId || !/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(taskId)) {
  throw new Error('UUID inválido');
}

return {
  json: {
    ...$input.item.json,
    task_id: taskId
  }
};

// Formatar resposta para listagens de tarefas
const items = $input.all();

if (items.length === 0) {
  return {
    json: {
      response: 'Nenhuma tarefa encontrada.'
    }
  };
}

const formatDate = (dateStr) => {
  if (!dateStr) return 'N/A';
  const date = new Date(dateStr);
  return date.toLocaleDateString('pt-BR', { timeZone: 'America/Sao_Paulo' });
};

let response = `📋 Tarefas encontradas: ${items.length}\n\n`;

items.forEach((item, index) => {
  const t = item.json;
  const statusEmoji = {
    'ANDA': '🟡',
    'PROG': '🔵',
    'CONC': '✅',
    'CANC': '❌',
    'RPAR': '🔄'
  }[t.status_codigo] || '⚪';

  response += `${index + 1}. ${statusEmoji} [${t.status_codigo}] ${t.tarefa}\n`;
  response += `   Local: ${t.locais_nomes} | Executor: ${t.executores_nomes}\n`;
  response += `   Início: ${formatDate(t.data_inicio)} | Fim: ${formatDate(t.data_fim)}\n`;
  response += `   ID: ${t.id}\n`;
  if (t.telegram_topic_id) {
    response += `   TG: topic_id ${t.telegram_topic_id}\n`;
  }
  response += '\n';
});

return {
  json: {
    response: response.trim()
  }
};

// Formatar resposta para ordem/nota/si
const item = $input.item.json;

if (!item.ordem && !item.nota && !item.si) {
  return {
    json: {
      response: 'Ordem/Nota/SI não encontrada ou sem vínculo com tarefas acessíveis para você.'
    }
  };
}

let response = '';
if (item.ordem) {
  response = `📄 Ordem: ${item.ordem}\n`;
  if (item.descricao) response += `   ${item.descricao}\n`;
  if (item.data_emissao) {
    const date = new Date(item.data_emissao);
    response += `   Emissão: ${date.toLocaleDateString('pt-BR', { timeZone: 'America/Sao_Paulo' })}\n`;
  }
  if (item.task_ids) {
    response += `\n   Vinculada a tarefas: ${item.task_nomes}\n`;
    response += `   IDs: ${item.task_ids}`;
  }
} else if (item.nota) {
  response = `📋 Nota: ${item.nota}\n`;
  if (item.descricao) response += `   ${item.descricao}\n`;
  if (item.task_ids) {
    response += `\n   Vinculada a tarefas: ${item.task_nomes}\n`;
    response += `   IDs: ${item.task_ids}`;
  }
} else if (item.si) {
  response = `📑 SI: ${item.si}\n`;
  if (item.descricao) response += `   ${item.descricao}\n`;
  if (item.task_ids) {
    response += `\n   Vinculado a tarefas: ${item.task_nomes}\n`;
    response += `   IDs: ${item.task_ids}`;
  }
}

return {
  json: {
    response: response.trim()
  }
};

// Formatar resposta para links SAP de uma tarefa
const item = $input.item.json;

let response = '🔗 Links SAP:\n\n';

if (item.ordens && item.ordens !== 'Nenhuma') {
  response += `📄 Ordens: ${item.ordens}\n`;
} else {
  response += '📄 Ordens: Nenhuma\n';
}

if (item.notas && item.notas !== 'Nenhuma') {
  response += `📋 Notas: ${item.notas}\n`;
} else {
  response += '📋 Notas: Nenhuma\n';
}

if (item.sis && item.sis !== 'Nenhum') {
  response += `📑 SIs: ${item.sis}\n`;
} else {
  response += '📑 SIs: Nenhum\n';
}

if (item.telegram_topic_id) {
  response += `\nTG: topic_id ${item.telegram_topic_id}`;
}

return {
  json: {
    response: response.trim()
  }
};

// Formatar resposta para mensagens de chat
const items = $input.all();

if (items.length === 0) {
  return {
    json: {
      response: 'Nenhuma mensagem encontrada.'
    }
  };
}

const formatDateTime = (dateStr) => {
  if (!dateStr) return 'N/A';
  const date = new Date(dateStr);
  return date.toLocaleString('pt-BR', { 
    timeZone: 'America/Sao_Paulo',
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit'
  });
};

let response = `💬 Últimas mensagens (Tarefa: ${items[0]?.json?.tarefa_nome || 'N/A'}):\n\n`;

// Reverter ordem (mais antigas primeiro)
items.reverse().forEach((item) => {
  const m = item.json;
  const sourceEmoji = m.source === 'telegram' ? '📱' : '📲';
  response += `[${formatDateTime(m.created_at)}] ${m.autor_nome} ${sourceEmoji}:\n`;
  response += `  ${m.conteudo}\n\n`;
});

return {
  json: {
    response: response.trim()
  }
};

return {
  json: {
    response: 'Você não tem acesso a essa tarefa.'
  }
};

return {
  json: {
    response: 'Comando não reconhecido. Use: vencendo, hoje, status <codigo>, tarefa <texto>, id <uuid>, ordem <num>, nota <num>, si <num>, sap <uuid>, chat <uuid>'
  }
};

return {
  json: {
    response: 'Usuário não identificado. Verifique se sua conta Telegram está vinculada.'
  }
};
